import { Link, useIntl } from 'gatsby-plugin-intl';
import React, { ReactNode } from 'react';
import { WithInjectedModalGalleryProps } from 'src/hoc/withModalGallery';

import { Colors, Material } from '@constants';
import { withModalGallery } from '@hoc';
import { Grid, ButtonBase, makeStyles } from '@material-ui/core';
import { COLORS } from "@theme";
import ColorsList from './ColorsList';
import Data from './Data';
import Description from './Description';
import MaterialsList from './MaterialsList';
import Price from './Price';
import { TH4Sans } from '@components';

const useStyles = makeStyles(theme => ({
  container: {
    transform: 'scale(1)',
    marginTop: theme.spacing(2),
  },
  data: {
    padding: theme.spacing(1),
    display: 'flex',
    flexDirection: 'column',
    alignContent: 'center',
    justifyContent: 'center',
    minHeight: '100%',
  },
  button: {
    backgroundColor: theme.palette.common.white,
    paddingBottom: '100%',
    position: 'relative',
    width: '100%',
  },
  image: {
    position: 'absolute',
    width: '100%',
    top: 0,
    marginTop: '50%',
    transform: 'translateY(-50%)',
  },
  title: {
    color: COLORS.BLACK,
    textTransform: 'uppercase',
    marginBottom: theme.spacing(1),
  }
}))

const Product = withModalGallery(({ images, open, vertical, price, url, name, description, ...attributes }: Props & WithInjectedModalGalleryProps) => {
  const Tag = url ? Link : "div"
  const span = vertical ? 12 : (12 / (images.length + 1))
  const { formatMessage, formatNumber } = useIntl()
  const classes = useStyles()

  return (
    <Tag to={url} className={`${classes.container}`}>
      <Grid container spacing={5}>
        {images.map(image => (
          <Grid item xs={span} key={image.src} onClick={() => open(image)}>
            <ButtonBase className={classes.button}>
              <img src={image.src} alt={name} className={classes.image} />
            </ButtonBase>
          </Grid>
        ))}
        <Grid item xs={span}>
          <div className={classes.data}>
            <TH4Sans className={classes.title}>{name}</TH4Sans>

            <Description description={description} />

            {Object.keys(attributes).map(name => {
              let valueToPrint

              switch (name) {
                case "materials":
                  valueToPrint = <MaterialsList materials={attributes[name]!} />
                  break

                case "colors":
                  valueToPrint = <ColorsList colors={attributes[name]!} />
                  break

                case "weight":
                  valueToPrint = formatNumber(attributes[name]!, { style: "unit", unit: "kilogram" })
                  break

                case "diameter":
                case "thickness":
                case "height":
                case "length":
                case "depth":
                case "width":
                  valueToPrint = formatNumber(attributes[name]! / 10, { style: "unit", unit: "centimeter" })
                  break
              }
              return (
                <Data 
                  key={name} 
                  label={formatMessage({ id: `PRODUCT__attributo__${name}` })}
                  value={valueToPrint}
                />
              )
            })}

            <Price price={price} />
          </div>
        </Grid>
      </Grid>
    </Tag>
  )
})

interface Props {
  colors?: Colors[]
  materials?: Material[]
  name: string
  description?: string | ReactNode
  depth?: number
  diameter?: number
  height?: number
  length?: number
  vertical?: boolean
  thickness?: number
  url?: string
  weight?: number
  width?: number
  price?: number
}

export default Product
